import React, { useState, useEffect } from 'react';
import { Users, BookOpen, Briefcase, Key } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, LineChart, Line } from 'recharts';
import { reportsAPI } from '../services/api';
import { Card, Spinner } from './ui';

export default function Dashboard() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const { data } = await reportsAPI.employeesByDeptRole();
        setStats(data);
      } catch (e) {
        console.error('Failed to load stats', e);
      } finally {
        setLoading(false);
      }
    };
    fetchStats();
  }, []);

  const displayStats = [
    { label: "Total Employees", value: "124", icon: <Users size={24} />, colorClass: "purple" },
    { label: "Departments", value: "8", icon: <Briefcase size={24} />, colorClass: "orange" },
    { label: "Active Roles", value: "14", icon: <Key size={24} />, colorClass: "coral" }
  ];

  const dummyAttendanceData = [
    { name: 'Mon', present: 110, absent: 14 },
    { name: 'Tue', present: 115, absent: 9 },
    { name: 'Wed', present: 118, absent: 6 },
    { name: 'Thu', present: 105, absent: 19 },
    { name: 'Fri', present: 120, absent: 4 },
  ];

  const CustomTooltip = ({ active, payload, label }) => {
    if (active && payload && payload.length) {
      return (
        <div style={{ background: 'var(--white)', padding: 12, border: '1px solid var(--border-color)', borderRadius: 8, boxShadow: 'var(--shadow)' }}>
          <p style={{ margin: 0, fontWeight: 600, color: 'var(--text-dark)' }}>{label}</p>
          {payload.map((entry, index) => (
            <p key={`item-${index}`} style={{ margin: 0, color: entry.color, fontSize: 13 }}>
              {entry.name}: {entry.value}
            </p>
          ))}
        </div>
      );
    }
    return null;
  };

  return (
    <div className="dashboard" style={{ animation: 'fadeIn 0.25s ease-out' }}>
      <h1 className="page-title" style={{ marginBottom: '24px' }}>Overview Dashboard</h1>

      {/* Stats Grid */}
      <div className="dashboard-grid" style={{ marginTop: 0 }}>
        {displayStats.map((stat, i) => (
          <div className="stat-card" key={i}>
            <div className={`stat-icon ${stat.colorClass || 'purple'}`}>
              {stat.icon}
            </div>
            <div className="stat-info">
              <div className="stat-value">{stat.value}</div>
              <div className="stat-label">{stat.label}</div>
            </div>
          </div>
        ))}
      </div>

      {loading ? (
        <div style={{ display: 'flex', justifyContent: 'center', padding: 60 }}><Spinner /></div>
      ) : (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(400px, 1fr))', gap: '24px', marginTop: '24px' }}>

          {/* Chart 1: Department Distribution */}
          <Card style={{ padding: '24px' }}>
            <h3 style={{ fontSize: 16, marginBottom: 20 }}>Employee Distribution by Department</h3>
            <div style={{ height: 300 }}>
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={stats || []}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="var(--gray-200)" />
                  <XAxis dataKey="department_name" tick={{ fill: 'var(--gray-500)', fontSize: 12 }} axisLine={false} tickLine={false} />
                  <YAxis tick={{ fill: 'var(--gray-500)', fontSize: 12 }} axisLine={false} tickLine={false} />
                  <Tooltip content={<CustomTooltip />} cursor={{ fill: 'var(--gray-100)' }} />
                  <Bar dataKey="employee_count" name="Employees" fill="var(--primary)" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </Card>

          {/* Chart 2: Weekly Attendance Trend */}
          <Card style={{ padding: '24px' }}>
            <h3 style={{ fontSize: 16, marginBottom: 20 }}>Weekly Attendance Trends</h3>
            <div style={{ height: 300 }}>
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={dummyAttendanceData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="var(--gray-200)" />
                  <XAxis dataKey="name" tick={{ fill: 'var(--gray-500)', fontSize: 12 }} axisLine={false} tickLine={false} />
                  <YAxis tick={{ fill: 'var(--gray-500)', fontSize: 12 }} axisLine={false} tickLine={false} />
                  <Tooltip content={<CustomTooltip />} />
                  <Line type="monotone" dataKey="present" name="Present" stroke="var(--success)" strokeWidth={3} dot={{ r: 4, strokeWidth: 2 }} activeDot={{ r: 6 }} />
                  <Line type="monotone" dataKey="absent" name="Absent" stroke="var(--danger)" strokeWidth={3} dot={{ r: 4, strokeWidth: 2 }} activeDot={{ r: 6 }} />
                </LineChart>
              </ResponsiveContainer>
            </div>
          </Card>
        </div>
      )}
    </div>
  );
}
